#include <stdio.h>

typedef struct {
    int pid;
    char name[16];
    float cpu;
    int mem_kb;
} ProcInfo;

int main(void) {
    ProcInfo procs[] = {
        {1, "init", 0.1f, 2048},
        {42, "bash", 1.5f, 8192},
        {1337, "gcc", 95.2f, 524288},
    };
    int n = 3;
    printf("%4s|%-10s|%6s|%8s\n", "PID", "NAME", "CPU%", "MEM(KB)");
    printf("----+----------+-------+--------\n");
    for (int i = 0; i < n; i++) {
        printf("%4d|%-10s|%6.1f|%8d\n",
               procs[i].pid, procs[i].name,
               procs[i].cpu, procs[i].mem_kb);
    }
    return 0;
}

